import React, { useState, useEffect } from 'react';
import io from 'socket.io-client';
import './App.css';

const socket = io('http://localhost:5001');

function App() {
  const [lessons, setLessons] = useState([]);
  const [groups, setGroups] = useState([]);
  const [progress, setProgress] = useState([]);
  const [currentLesson, setCurrentLesson] = useState(null);
  const [score, setScore] = useState(0);
  const [badge, setBadge] = useState('');
  const [doubtMessages, setDoubtMessages] = useState([]);
  const [message, setMessage] = useState('');

  useEffect(() => {
    fetch('http://localhost:5001/api/lessons')
      .then(res => res.json())
      .then(data => setLessons(data))
      .catch(err => console.error('Error fetching lessons:', err));
    fetch('http://localhost:5001/api/groups')
      .then(res => res.json())
      .then(data => setGroups(data))
      .catch(err => console.error('Error fetching groups:', err));
    fetch('http://localhost:5001/api/progress')
      .then(res => res.json())
      .then(data => setProgress(data))
      .catch(err => console.error('Error fetching progress:', err));

    socket.on('receive-message', (data) => {
      setDoubtMessages(prev => [...prev, data]);
    });
  }, []);

  const handleQuizSubmit = (answers) => {
    const correct = answers.filter(a => a.correct).length;
    setScore(correct);
    if (correct === 1) setBadge('CSS Beginner!');
  };

  const joinGroup = (groupId) => {
    fetch('http://localhost:5001/api/groups/join', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ groupId, userId: 1 }) // Assuming userId 1 for demo
    });
  };

  const sendDoubtMessage = () => {
    socket.emit('send-message', { room: 'doubts', message });
    setMessage('');
  };

  return (
    <div className="container mx-auto p-4">
      <h1 className="text-3xl font-bold text-blue-600">Coding Lesson App</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <h2 className="text-2xl text-green-600">Lessons</h2>
          {lessons.map(lesson => (
            <div key={lesson.id} className="bg-white p-4 rounded shadow mb-4">
              <h3 className="font-bold">{lesson.title}</h3>
              <p>{lesson.content}</p>
              <button onClick={() => setCurrentLesson(lesson)} className="bg-blue-500 text-white px-4 py-2 rounded">Take Quiz</button>
            </div>
          ))}
        </div>
        <div>
          {currentLesson && (
            <div className="bg-gray-100 p-4 rounded">
              <h2>Quiz: {currentLesson.title}</h2>
              {currentLesson.quiz.questions.map(q => (
                <div key={q.id}>
                  <p>{q.question}</p>
                  {q.options.map((opt, idx) => (
                    <button key={idx} onClick={() => handleQuizSubmit([{ correct: idx === q.correct }])} className="bg-blue-500 text-white px-2 py-1 rounded mr-2">{opt}</button>
                  ))}
                </div>
              ))}
            </div>
          )}
          <div className="mt-4">
            <p>Score: {score}</p>
            {badge && <span className="bg-yellow-400 px-2 py-1 rounded">{badge}</span>}
          </div>
          <h2 className="text-2xl mt-4">Groups</h2>
          {groups.map(group => (
            <div key={group.id} className="bg-white p-4 rounded shadow mb-2">
              <h3>{group.name}</h3>
              <button onClick={() => joinGroup(group.id)} className="bg-green-500 text-white px-2 py-1 rounded">Join</button>
              <p>Members: {group.members.length}</p>
            </div>
          ))}
          <h2 className="text-2xl mt-4">Shared Progress</h2>
          {progress.map(p => (
            <p key={p.id}>{p.user.email}: {p.score}</p>
          ))}
          <h2 className="text-2xl mt-4">Doubt Sessions</h2>
          <div className="bg-white p-4 rounded shadow">
            {doubtMessages.map((msg, idx) => (
              <p key={idx}>{msg.message}</p>
            ))}
            <input value={message} onChange={(e) => setMessage(e.target.value)} className="border p-2 w-full" />
            <button onClick={sendDoubtMessage} className="bg-purple-500 text-white px-4 py-2 rounded mt-2">Send</button>
          </div>
        </div>
      </div>
    </div>
  );
}

export default App;
